import{_ as a,o,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"CoPoS 全產業鏈深度研究：04 下游需求動能","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/CoPoS/04_下游需求.md","filePath":"Deep32Q知識庫/產業洞察/CoPoS/04_下游需求.md"}'),t={name:"Deep32Q知識庫/產業洞察/CoPoS/04_下游需求.md"};function r(n,e,s,d,c,h){return o(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="copos-全產業鏈深度研究-04-下游需求動能" tabindex="-1">CoPoS 全產業鏈深度研究：04 下游需求動能 <a class="header-anchor" href="#copos-全產業鏈深度研究-04-下游需求動能" aria-label="Permalink to &quot;CoPoS 全產業鏈深度研究：04 下游需求動能&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>CoPoS 的最大推動力來自 AI 晶片持續大型化與異質整合密度提升。從 NVIDIA 的路線來看，Rubin 世代將帶動 CoWoS-L 大量使用，但進入 Rubin Ultra 與 Feynman 時代後，封裝尺寸與整合複雜度將進一步上升，使面板化封裝的戰略價值明顯提升。</p><p>市場目前對 CoPoS 的需求想像，主要來自三項核心趨勢：第一，AI GPU 封裝需容納更多 HBM 與 chiplet；第二，單一封裝正走向更大 reticle 尺寸；第三，CPO、電源整合與系統級封裝的比重持續上升。這些趨勢都指向同一個結論：傳統圓形晶圓封裝將越來越難滿足下一代旗艦 AI 晶片需求。</p><p>換言之，CoPoS 的需求不是憑空出現的技術 push，而是從 NVIDIA、AMD、Google 等 AI 大客戶的產品路線推導出來的結構性需要。</p><h2 id="事實與數據" tabindex="-1">事實與數據 <a class="header-anchor" href="#事實與數據" aria-label="Permalink to &quot;事實與數據&quot;">​</a></h2><ul><li>產業與技術媒體指出，NVIDIA Rubin 將採用 TSMC N3P 製程與 CoWoS-L 封裝，搭配 HBM4。來源：TechPowerUp 等技術媒體。</li><li>有報導指出，NVIDIA Rubin Ultra 原規畫可能升級到四 die、16 顆 HBM4E 的超大封裝，但因翹曲與熱應力問題，最後可能調整設計。來源：TweakTown、Chipstrat。</li><li>多篇分析指出，NVIDIA Feynman 與下一代 AI GPU 很可能進一步導入面板級封裝，作為超大中介層的解決方案。來源：TechPowerUp、Seeking Alpha、SmBom。</li><li>部分分析認為，若 NVIDIA 採用 Feynman 世代架構，封裝將進入更大介面積、更多 HBM、甚至 CPO 整合的路線，對 CoPoS 平台形成明確需求。來源：WCCFTech、半導體產業分析。</li><li>TrendForce 與產業報導亦指出，CoPoS 首波最受關注的應用場景就是 AI GPU 與 AI ASIC。來源：TrendForce、經濟日報。</li></ul><h2 id="產業意涵" tabindex="-1">產業意涵 <a class="header-anchor" href="#產業意涵" aria-label="Permalink to &quot;產業意涵&quot;">​</a></h2><p>CoPoS 的需求動能並非單一客戶事件，而是 AI 計算架構演進下的必然結果。只要大型語言模型、推論叢集、AI 交換器與高頻寬系統持續擴張，封裝尺寸與異質整合需求就會持續上升，進而推動面板化封裝進入主流。</p><p>這也代表 CoPoS 的受惠族群不僅限於 NVIDIA 供應鏈，只要 AMD、Google、Broadcom 等客戶也在尋求更大封裝方案，產業需求基礎就會更穩固。對台灣而言，這是一次從供應商升級為平台共建者的機會。</p><h2 id="來源引用" tabindex="-1">來源引用 <a class="header-anchor" href="#來源引用" aria-label="Permalink to &quot;來源引用&quot;">​</a></h2><ul><li>TechPowerUp，《News Posts matching CoWoS-L》</li><li>TweakTown，《NVIDIA Rubin Ultra reportedly sticking to a dual-die design instead of a four-die plan》</li><li>Seeking Alpha，《Nvidia reveals its biggest expansion to CUDA since its 2006 launch》</li><li>SmBom，《TSMC CoPoS to Launch in 2028, NVIDIA Feynman Adopts》</li><li>TrendForce，《TSMC Speeds Advanced Packaging: AP7 Targets 2026 Output; Arizona P6 Eyed for U.S. Packaging Hub》</li></ul><h2 id="風險與不確定性提醒" tabindex="-1">風險與不確定性提醒 <a class="header-anchor" href="#風險與不確定性提醒" aria-label="Permalink to &quot;風險與不確定性提醒&quot;">​</a></h2><ul><li>NVIDIA Rubin Ultra 的 die 數量與 HBM 整合方案目前仍有版本差異，不同媒體說法不盡相同。</li><li>若 CoWoS-L 持續改善，部分客戶可能延後導入 CoPoS。</li><li>AI 資本支出若因市場或政策因素放緩，先進封裝需求成長曲線可能出現波動。</li><li>CPO 整合進度亦可能影響 CoPoS 的首波應用範圍與優先順序。</li></ul>',14)])])}const u=a(t,[["render",r]]);export{p as __pageData,u as default};
